sql:
SELECT name 
FROM tournaments 
WHERE status = 'ongoing';

SELECT COUNT(*) AS active_tournaments
FROM tournaments
WHERE status = 'Active';

SELECT DISTINCT p.name
FROM players p
JOIN match_results mr ON p.player_id = mr.winner_id;

SELECT player_id, SUM(points) AS total_points
FROM standings
GROUP BY player_id;

SELECT player_id, points
FROM standings
ORDER BY points DESC;

SELECT sport, COUNT(tournament_id) AS number_of_tournaments
FROM tournaments
GROUP BY sport;

SELECT players.name, standings.total_points
FROM standings
JOIN players ON standings.player_id = players.player_id;

external_knowledge:
- "Step onto the podium" metaphorically refers to ranking among the top 3 in the standings;
- "Tournaments concluded by the end of February 2023" means the end date is less than or equal to '2023-02-28';
- "Victories, defeats, points scored, and final position" correspond to wins, losses, points, and rank, respectively, in the SQL query.

- 'Great Tournament' refers to the actual tournament name;
- 'top contenders' and 'shining with their accumulated glory' are metaphorical expressions for players with the highest ranks and total points;
- 'first, second, and third beacons of triumph' symbolize the players ranked 1st, 2nd, and 3rd.

sql:
SELECT COUNT(m.match_id) AS total_matches
FROM matches m
WHERE m.tournament_id = 1;

SELECT COUNT(*) AS completed_matches
FROM matches
WHERE status = 'Completed';
